using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Linq;
using System.Threading.Tasks;

namespace MyApp.Controllers
{
    public class FileUploadController : ControllerBase
    {
        [HttpPost]
        public async Task<IActionResult> UploadFile()
        {
            // Get the file from the request body
            var file = Request.Form.Files[0];

            // Check if the file is valid and supported
            if (file == null || !(file.ContentType.StartsWith("image") || file.ContentType.StartsWith("application/pdf") || file.ContentType.StartsWith("application/vnd.openxmlformats-officedocument")))
            {
                return BadRequest();
            }

            // Save the file to the wwwroot/uploads directory
            var uploadsDir = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot", "uploads");
            var fileName = $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}";
            var filePath = Path.Combine(uploadsDir, fileName);
            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                await file.CopyToAsync(stream);
            }

            // Return the file path
            return Ok($"{fileName}");
        }
    }
}